mapper.select:
    	/* com.erns.coching.rawType.mapper.RawTypeDAO.getList */

    	SELECT B.* FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() AS TOTAL FROM (
					SELECT

					    , BB.CODE_NAME AS GRP_CODE_NM
				    FROM  T_CM_RAW_TYPE AA
					INNER JOIN T_CODE_INF BB
						ON AA.GRP_CODE = BB.CODE AND BB.GRP_CODE ='CH001'



				ORDER BY AA.GRP_CODE, AA.SORT_ORD
			) A
		) B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

mapper.insert:
    	/* com.erns.coching.rawType.mapper.RawTypeDAO.insert */


			WITH max_code AS (
				SELECT
					LPAD(CAST(COALESCE(MAX(CAST(code AS INTEGER)), 0) + 1 AS TEXT), 3, '0') AS next_code,
					COALESCE(MAX(sort_ord), 0) + 1 as next_ord
				FROM T_CM_RAW_TYPE
				WHERE GRP_CODE = #{grpCode}
			)
			SELECT
				nextval('seq_t_cm_raw_type') AS typeSeq,
				next_code AS code,
				next_ord AS sortOrd
			FROM max_code


    	INSERT INTO T_CM_RAW_TYPE (
    		  TYPE_SEQ
			, GRP_CODE
			, CODE
			, CODE_NM_KO
			, CODE_NM_EN
			, INPT_TYPE
			, USE_YN
			, SORT_ORD
			, RGTR
			, RGT_DTTM
    	) VALUES (
			  #{typeSeq		, jdbcType=INTEGER}
			, #{grpCode		, jdbcType=VARCHAR}
			, #{code		, jdbcType=VARCHAR}
			, #{codeNmKo	, jdbcType=VARCHAR}
			, #{codeNmEn	, jdbcType=VARCHAR}
			, #{inptType	, jdbcType=VARCHAR}
			, COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')
			, #{sortOrd		, jdbcType=VARCHAR}
			, #{rgtr		, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.rawType.mapper.RawTypeDAO.update */

    	UPDATE T_CM_RAW_TYPE SET
			  CODE_NM_KO      	= #{codeNmKo	, jdbcType=VARCHAR}
			, CODE_NM_EN        = #{codeNmEn	, jdbcType=VARCHAR}
			, USE_YN        	= COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')

			, CHNR 		 		= #{chnr, jdbcType=INTEGER}
			, CHNG_DTTM  		= now()
		where
			TYPE_SEQ 		= #{typeSeq		, jdbcType=INTEGER}

    	/* com.erns.coching.rawType.mapper.RawTypeDAO.updateUseYn */

    	UPDATE T_RAW_MST SET
			  USE_YN            = COALESCE(#{useYn	, jdbcType=CHAR}, 'N')

			, CHNR 		 		= #{chnr	, jdbcType=INTEGER}
			, CHNG_DTTM  		= now()

			AND RAW_SEQ 		= #{rawSeq	, jdbcType=INTEGER}

    	/* com.erns.coching.rawType.mapper.RawTypeDAO.updateState */

    	UPDATE T_CM_RAW_TYPE SET
			  USE_YN        	= COALESCE(#{useYn	, jdbcType=CHAR}, 'Y')

			, CHNR 		 		= #{chnr, jdbcType=INTEGER}
			, CHNG_DTTM  		= now()

			TYPE_SEQ 		= #{typeSeq		, jdbcType=INTEGER}
